external_knowledge:
- "hopefuls" refers to the candidates running for positions;
- "type of governmental group" refers to the government bodies categorized by the number of seats they have;
- "spots available" indicates the `no_of_seats` in each government body.

sql:
SELECT election_type, voter_turnout
FROM elections
WHERE voter_turnout = (
    SELECT MAX(voter_turnout)
    FROM elections
);

SELECT no_of_women, percentage, geographical_area 
FROM representation 
WHERE last_updated = '2023-10-01';

SELECT candidates.name 
FROM candidates 
INNER JOIN appointments ON candidates.candidate_id = appointments.candidate_id;

SELECT body_name, no_of_seats
FROM government_bodies
WHERE no_of_seats = (
  SELECT MAX(no_of_seats)
  FROM government_bodies
) AND established_date < '2000-01-01';

